import{c as a,Q as t,j as n,m as o}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I assign Account Manager scope?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/account-manager-scope.md","filePath":"guide/recipes/admin/account-manager-scope.md","lastUpdated":1779094756000}'),s={name:"guide/recipes/admin/account-manager-scope.md"};function i(r,e,c,l,d,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="how-do-i-assign-account-manager-scope" tabindex="-1">How do I assign Account Manager scope? <a class="header-anchor" href="#how-do-i-assign-account-manager-scope" aria-label="Permalink to &quot;How do I assign Account Manager scope?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> only</p></div><p>Account Managers see only the customers in their scope — rows outside the scope simply don&#39;t appear in their lists. Scope is mandatory: an AM with empty scope sees nothing.</p><h2 id="at-invite-time" tabindex="-1">At invite time <a class="header-anchor" href="#at-invite-time" aria-label="Permalink to &quot;At invite time&quot;">​</a></h2><p>The scope picker appears when you tick <strong>Account Manager</strong> on the <a href="./create-internal-user">invite form</a>. Pick at least one customer before sending the invite.</p><h2 id="on-an-existing-user" tabindex="-1">On an existing user <a class="header-anchor" href="#on-an-existing-user" aria-label="Permalink to &quot;On an existing user&quot;">​</a></h2><ol><li>Open <strong>Internal Users</strong> and click the user.</li><li>Make sure they have the <strong>Account Manager</strong> role checked.</li><li>In the <strong>Customer Scope</strong> section, click <strong>Grant Customer</strong>.</li><li>Search and pick. Add as many as needed.</li><li>To revoke, click the X on a granted customer chip.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The scope takes effect on the user&#39;s next page load. Lists (Customers, Tenants, Billing) hide everything outside scope. The user can&#39;t search or URL-hack their way into customers they don&#39;t own.</p><div class="tip custom-block"><p class="custom-block-title">Combine with Finance Admin</p><p>An AM with only Account Manager role sees scoped customers&#39; billing. Adding Finance Admin gives them billing visibility across <em>all</em> customers — useful for finance leads who also handle a customer book.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./qa-admin-scope">How do I assign QA Admin scope?</a></li><li><a href="./create-internal-user">How do I create an internal user?</a></li></ul>',12)])])}const m=a(s,[["render",i]]);export{p as __pageData,m as default};
